import React, { useState, useRef } from 'react';
import 'bootstrap/dist/css/bootstrap.min.css';
import './AuthPage.css';

const AuthPage = () => {
  const [isLogin, setIsLogin] = useState(true);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
    remember: false
  });
  const [errors, setErrors] = useState({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const formRef = useRef(null);

  const [focusedInputs, setFocusedInputs] = useState({});

  const handleFocus = (inputName) => {
    setFocusedInputs(prev => ({ ...prev, [inputName]: true }));
  };

  const handleBlur = (inputName) => {
    setFocusedInputs(prev => ({ ...prev, [inputName]: false }));
  };

  const validateEmail = (email) => {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return re.test(email);
  };

  const validateForm = () => {
    const newErrors = {};

    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!validateEmail(formData.email)) {
      newErrors.email = 'Email is invalid';
    }

    if (!formData.password.trim()) {
      newErrors.password = 'Password is required';
    } else if (formData.password.length < 6) {
      newErrors.password = 'Password must be at least 6 characters';
    }

    if (!isLogin) {
      if (!formData.name.trim()) {
        newErrors.name = 'Full name is required';
      }
      if (!formData.confirmPassword.trim()) {
        newErrors.confirmPassword = 'Confirm password is required';
      } else if (formData.password !== formData.confirmPassword) {
        newErrors.confirmPassword = 'Passwords do not match';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));

    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: '' }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);

    if (validateForm()) {
      try {
        await new Promise(resolve => setTimeout(resolve, 2000));
        if (isLogin) {
          alert('Login successful! (Demo)');
        } else {
          alert('Sign up successful! (Demo)');
        }
        setFormData({
          name: '',
          email: '',
          password: '',
          confirmPassword: '',
          remember: false
        });
      } catch (error) {
        alert('Error occurred. Please try again.');
      }
    }

    setIsSubmitting(false);
  };

  const toggleForm = () => {
    setIsLogin(!isLogin);
  };

  return (
    <div className="auth-container">
      <div className="split-screen">
        <div className="left-panel">
          <i className="bi bi-person-badge logo-icon"></i>
          <h1>Bousalaty</h1>
          <p>
            Welcome to your educational journey.
            <br />
            Discover majors and build your future.
          </p>
        </div>

        <div className="right-panel">
          <div className="form-card">
            <div className="form-switcher">
              <h2>{isLogin ? 'Welcome Back' : 'Create Account'}</h2>
              <p>
                {isLogin
                  ? 'Please sign in to your account'
                  : 'Join us today and start your journey'}
              </p>
            </div>

            <form ref={formRef} onSubmit={handleSubmit} noValidate>
              {!isLogin && (
                <div className="form-floating form-content show">
                  <i className={`bi bi-person input-icon ${focusedInputs.name ? 'focused' : ''}`}></i>
                  <input
                    type="text"
                    className="form-control"
                    id="name"
                    name="name"
                    placeholder="Full Name"
                    value={formData.name}
                    onChange={handleInputChange}
                    onFocus={() => handleFocus('name')}
                    onBlur={() => handleBlur('name')}
                    required
                  />
                  <label htmlFor="name">Full Name</label>
                  {errors.name && <div className="error-message">{errors.name}</div>}
                </div>
              )}

              <div className="form-floating form-content show">
                <i className={`bi bi-envelope input-icon ${focusedInputs.email ? 'focused' : ''}`}></i>
                <input
                  type="email"
                  className="form-control"
                  id="email"
                  name="email"
                  placeholder="name@example.com"
                  value={formData.email}
                  onChange={handleInputChange}
                  onFocus={() => handleFocus('email')}
                  onBlur={() => handleBlur('email')}
                  required
                />
                <label htmlFor="email">Email address</label>
                {errors.email && <div className="error-message">{errors.email}</div>}
              </div>

              <div className="form-floating form-content show">
                <i className={`bi bi-lock input-icon ${focusedInputs.password ? 'focused' : ''}`}></i>
                <input
                  type="password"
                  className="form-control"
                  id="password"
                  name="password"
                  placeholder="Password"
                  value={formData.password}
                  onChange={handleInputChange}
                  onFocus={() => handleFocus('password')}
                  onBlur={() => handleBlur('password')}
                  required
                />
                <label htmlFor="password">Password</label>
                {errors.password && <div className="error-message">{errors.password}</div>}
              </div>

              {!isLogin && (
                <div className="form-floating form-content show">
                  <i className={`bi bi-lock-fill input-icon ${focusedInputs.confirmPassword ? 'focused' : ''}`}></i>
                  <input
                    type="password"
                    className="form-control"
                    id="confirmPassword"
                    name="confirmPassword"
                    placeholder="Confirm Password"
                    value={formData.confirmPassword}
                    onChange={handleInputChange}
                    onFocus={() => handleFocus('confirmPassword')}
                    onBlur={() => handleBlur('confirmPassword')}
                    required
                  />
                  <label htmlFor="confirmPassword">Confirm Password</label>
                  {errors.confirmPassword && <div className="error-message">{errors.confirmPassword}</div>}
                </div>
              )}

              {isLogin && (
                <div className="form-check">
                  <input
                    className="form-check-input"
                    type="checkbox"
                    id="remember"
                    name="remember"
                    checked={formData.remember}
                    onChange={handleInputChange}
                  />
                  <label className="form-check-label" htmlFor="remember">
                    Remember me
                  </label>
                </div>
              )}

              <button
                type="submit"
                className="btn btn-primary mb-4"
                disabled={isSubmitting}
              >
                {isSubmitting ? (
                  <>
                    <span className="spinner-border spinner-border-sm me-2" role="status"></span>
                    {isLogin ? 'Signing In...' : 'Creating Account...'}
                  </>
                ) : (
                  isLogin ? 'Sign In' : 'Sign Up'
                )}
              </button>

              <div className="text-center">
                <a href="#" className="form-toggle" onClick={toggleForm}>
                  {isLogin
                    ? "Don't have an account? Sign up"
                    : 'Already have an account? Sign in'}
                </a>
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AuthPage;
